#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include <cuda_runtime.h>

#define MAX_ARGS 10
#define REC_LENGTH 49	
#define REC_WINDOW 10	
#define LATITUDE_POS 28	
#define OPEN 10000

struct neighbor {
	char entry[REC_LENGTH];
	double dist;
};

__global__ void compute_distances(float *z, float *latitudes, float *longitudes, 
                                   float target_lat, float target_long, int rec_count) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
        float tmp_lat = latitudes[i];
        float tmp_long = longitudes[i];
        z[i] = sqrt((tmp_lat - target_lat) * (tmp_lat - target_lat) + 
                    (tmp_long - target_long) * (tmp_long - target_long));
    }
}

int main(int argc, char* argv[]) {
    long long time0 = clock();
    FILE   *flist,*fp;
    int    i=0,j=0, k=0, rec_count=0, done=0;
    char   sandbox[REC_LENGTH * REC_WINDOW], *rec_iter,*rec_iter2, dbname[64];
    struct neighbor *neighbors = NULL;
    float target_lat, target_long, tmp_lat=0, tmp_long=0;

    if(argc < 5) {
        fprintf(stderr, "Invalid set of arguments\n");
        exit(-1);
    }

    flist = fopen(argv[1], "r");
    if(!flist) {
        printf("error opening flist\n");
        exit(1);
    }

    k = atoi(argv[2]);
    target_lat = atof(argv[3]);
    target_long = atof(argv[4]);

    neighbors = malloc(k*sizeof(struct neighbor));

    if(neighbors == NULL) {
        fprintf(stderr, "no room for neighbors\n");
        exit(0);
    }

    for( j = 0 ; j < k ; j++ ) { 
        neighbors[j].dist = OPEN;
    }

    if(fscanf(flist, "%s\n", dbname) != 1) {
        fprintf(stderr, "error reading filelist\n");
        exit(0);
    }

    fp = fopen(dbname, "r");
    if(!fp) {
        printf("error opening flist\n");
        exit(1);
    }

    float *z;
    z  = (float *) malloc(REC_WINDOW * sizeof(float));

    float *latitudes = (float *)malloc(REC_WINDOW * sizeof(float));
    float *longitudes = (float *)malloc(REC_WINDOW * sizeof(float));

    float *d_z;
    float *d_latitudes;
    float *d_longitudes;

    cudaMalloc(&d_z, REC_WINDOW * sizeof(float));
    cudaMalloc(&d_latitudes, REC_WINDOW * sizeof(float));
    cudaMalloc(&d_longitudes, REC_WINDOW * sizeof(float));

    while(!done) {

        rec_count = fread(sandbox, REC_LENGTH, REC_WINDOW, fp);
        if( rec_count != REC_WINDOW ) {
            if(!ferror(flist)) {
                fclose(fp);

                if(feof(flist))
                    done = 1;
                else {
                    if(fscanf(flist, "%s\n", dbname) != 1) {
                        fprintf(stderr, "error reading filelist\n");
                        exit(0);
                    }

                    fp = fopen(dbname, "r");

                    if(!fp) {
                        printf("error opening a db\n");
                        exit(1);
                    }
                }
            } else {
                perror("Error");
                exit(0);
            }
        }

        for (i = 0; i < rec_count; i++){
            rec_iter = sandbox+(i * REC_LENGTH + LATITUDE_POS - 1);
            latitudes[i] = atof(rec_iter);
            longitudes[i] = atof(rec_iter+5);
        }

        cudaMemcpy(d_latitudes, latitudes, rec_count * sizeof(float), cudaMemcpyHostToDevice);
        cudaMemcpy(d_longitudes, longitudes, rec_count * sizeof(float), cudaMemcpyHostToDevice);

        int threads_per_block = 256;
        int num_blocks = (rec_count + threads_per_block - 1) / threads_per_block;
        compute_distances<<<num_blocks, threads_per_block>>>(d_z, d_latitudes, d_longitudes, 
                                                              target_lat, target_long, rec_count);

        cudaMemcpy(z, d_z, rec_count * sizeof(float), cudaMemcpyDeviceToHost);

        for( i = 0 ; i < rec_count ; i++ ) {
            float max_dist = -1;
            int max_idx = 0;

            for( j = 0 ; j < k ; j++ ) {
                if( neighbors[j].dist > max_dist ) {
                    max_dist = neighbors[j].dist;
                    max_idx = j;
                }
            }

            if( z[i] < neighbors[max_idx].dist ) {
                sandbox[(i+1)*REC_LENGTH-1] = '\0';
                strcpy(neighbors[max_idx].entry, sandbox +i*REC_LENGTH);
                neighbors[max_idx].dist = z[i];
            }
        }
    }

    fprintf(stderr, "The %d nearest neighbors are:\n", k);
    for( j = 0 ; j < k ; j++ ) {
        if( !(neighbors[j].dist == OPEN) )
            fprintf(stderr, "%s --> %f\n", neighbors[j].entry, neighbors[j].dist);
    }

    fclose(flist);

    cudaFree(d_z);
    cudaFree(d_latitudes);
    cudaFree(d_longitudes);

    long long time1 = clock();
    printf("total time : %15.12f s", (float) (time1 - time0) / 1000000);
    return 0;
}
